const { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType } = require('docx');

const webhook = $('Webhook').first().json;
const title = webhook.body.title || 'Untitled Document';
const content = webhook.body.content || '';
const templateType = webhook.body.templateType || 'report';

const children = [];

// Title
children.push(new Paragraph({
  text: title,
  heading: HeadingLevel.HEADING_1,
  alignment: AlignmentType.CENTER,
  spacing: { after: 400 }
}));

// Generated date
children.push(new Paragraph({
  children: [new TextRun({
    text: 'Generated: ' + new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }),
    italics: true,
    size: 20,
    color: '666666'
  })],
  alignment: AlignmentType.CENTER,
  spacing: { after: 400 }
}));

// Separator
children.push(new Paragraph({
  border: { bottom: { style: 'single', size: 6, color: '999999' } },
  spacing: { after: 400 }
}));

// Content — supports basic markdown: ## headings, - bullets, plain text
for (const line of content.split('\n')) {
  if (line.startsWith('## ')) {
    children.push(new Paragraph({ text: line.slice(3), heading: HeadingLevel.HEADING_2, spacing: { before: 300, after: 200 } }));
  } else if (line.startsWith('### ')) {
    children.push(new Paragraph({ text: line.slice(4), heading: HeadingLevel.HEADING_3, spacing: { before: 200, after: 100 } }));
  } else if (line.startsWith('- ')) {
    children.push(new Paragraph({ text: line.slice(2), bullet: { level: 0 } }));
  } else if (line.trim()) {
    children.push(new Paragraph({ text: line, spacing: { after: 100 } }));
  } else {
    children.push(new Paragraph({ text: '' }));
  }
}

const doc = new Document({
  creator: 'DAX - Dakona AI Workspace',
  title: title,
  sections: [{ children }]
});

const buffer = await Packer.toBuffer(doc);
const fileName = title.replace(/[^a-zA-Z0-9 ]/g, '').replace(/\s+/g, '-') + '.docx';

return [{
  json: {
    title,
    fileName,
    fileSize: buffer.length,
    folderPath: webhook.body.folderPath || 'General'
  },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      fileName
    }
  }
}];
